#include "kernel_operator.h"
#include <cmath>

constexpr int32_t BUFFER_NUM = 2;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t outerDim,
                                uint32_t innerDim, uint32_t tileLength,
                                int32_t dim) {
        totalLen_ = totalLength;
        outerDim_ = outerDim;
        innerDim_ = innerDim;
        tileLen_ = tileLength;
        dim_ = dim;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalLen_ == 0 || tileLen_ == 0) return;
        uint32_t blockNum = AscendC::GetBlockNum();
        uint32_t blockIdx = AscendC::GetBlockIdx();
        // Grid-stride over rows
        for (uint32_t rowIdx = blockIdx; rowIdx < outerDim_; rowIdx += blockNum) {
            ProcessRow(rowIdx);
        }
    }

private:
    __aicore__ inline void ProcessRow(uint32_t rowIdx) {
        uint32_t rowOffset = rowIdx * innerDim_;
        uint32_t remaining = innerDim_;
        uint32_t pos = rowOffset;

        // Pass 1: Find row maximum
        float rowMax = -FLT_MAX;
        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[pos], curLen);
            AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
            AscendC::Max(tLocal, xLocal, rowMax, curLen);
            rowMax = tLocal(0);
            tmpQueue_.FreeTensor(tLocal);
            inQueueX_.FreeTensor(xLocal);
            pos += curLen;
            remaining -= curLen;
        }

        // Pass 2: Sum of exp(x - rowMax)
        float rowSum = 0.0f;
        pos = rowOffset;
        remaining = innerDim_;
        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[pos], curLen);
            AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
            // x - rowMax
            AscendC::Subs(tLocal, xLocal, rowMax, curLen);
            // exp
            AscendC::Exp(tLocal, tLocal, curLen);
            // sum elements in tile (manual loop)
            float tileSum = 0.0f;
            for (uint32_t i = 0; i < curLen; i++) {
                tileSum += tLocal(i);
            }
            rowSum += tileSum;
            tmpQueue_.FreeTensor(tLocal);
            inQueueX_.FreeTensor(xLocal);
            pos += curLen;
            remaining -= curLen;
        }

        // Pass 3: Output y = x - rowMax - log(rowSum)
        float logSum = __logf(rowSum);
        pos = rowOffset;
        remaining = innerDim_;
        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[pos], curLen);
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::Subs(yLocal, xLocal, rowMax, curLen);
            AscendC::Subs(yLocal, yLocal, logSum, curLen);
            AscendC::DataCopy(yGm_[pos], yLocal, curLen);
            outQueueY_.FreeTensor(yLocal);
            inQueueX_.FreeTensor(xLocal);
            pos += curLen;
            remaining -= curLen;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    uint32_t totalLen_ {0};
    uint32_t outerDim_ {1};
    uint32_t innerDim_ {0};
    uint32_t tileLen_ {0};
    int32_t dim_ {1};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.outerDim, tiling_data.innerDim, tiling_data.tileLength, tiling_data.dim);
    op.Process();
}
